import React, { useState } from "react";
import "../styles/GeneralChat.css";

const greetings = ["hi", "hello", "hey", "hai", "thanks", "thank"];

const GeneralChat = () => {
  const [messages, setMessages] = useState([
    {
      sender: "bot",
      text: "Hello. I’m glad you reached out today. How are you feeling right now?"
    }
  ]);
  const [input, setInput] = useState("");

  const therapistReply = (userText) => {
    const text = userText.toLowerCase();

    // If user just greets
    if (greetings.includes(text.trim())) {
      return "Hello. I’m glad you reached out today. How are you feeling right now?";
    }

    // If user says stressed / overwhelmed
    if (text.includes("stress") || text.includes("overwhelm")) {
      return "Thank you for sharing that. When you say you’re feeling overwhelmed, can you tell me a bit more about what’s been contributing to it?";
    }

    // If user mentions studies or family
    if (text.includes("study") || text.includes("exam") || text.includes("family")) {
      return "That sounds like a lot to manage at once. It’s understandable to feel this way. How have you been coping with this so far?";
    }

    // If user says they keep things inside
    if (text.includes("keep") || text.includes("inside") || text.includes("alone")) {
      return "I appreciate your honesty. Keeping things inside can be exhausting. We can explore healthier ways to process these feelings together, at a pace that feels comfortable for you.";
    }

    // Default therapist-style response
    return "Thank you for telling me. Can you help me understand a little more about how this has been affecting you day to day?";
  };

  const handleSend = () => {
    if (!input.trim()) return;

    const userMessage = { sender: "user", text: input };
    const botMessage = {
      sender: "bot",
      text: therapistReply(input)
    };

    setMessages([...messages, userMessage, botMessage]);
    setInput("");
  };

  return (
    <div className="chat-container">
      <h2 className="chat-title">General Therapy Chat</h2>

      <div className="chat-box">
        {messages.map((msg, index) => (
          <div
            key={index}
            className={`message ${msg.sender === "user" ? "user" : "bot"}`}
          >
            {msg.text}
          </div>
        ))}
      </div>

      <div className="chat-input">
        <input
          type="text"
          placeholder="Type your message..."
          value={input}
          onChange={(e) => setInput(e.target.value)}
        />
        <button onClick={handleSend}>Send</button>
      </div>
    </div>
  );
};

export default GeneralChat;
